// Utility: shuffle and pick N random questions
export function getRandomQuiz(subject: string, count: number = 10): QuizQuestion[] {
  const pool = quizBySubject[subject] || [];
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, Math.min(count, shuffled.length));
}

// Utility: get questions by difficulty
export function getQuizByDifficulty(subject: string, difficulty: "easy" | "medium" | "hard", count: number = 10): QuizQuestion[] {
  const pool = (quizBySubject[subject] || []).filter(q => q.difficulty === difficulty);
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, Math.min(count, shuffled.length));
}

// Utility: get questions focused on weak topics
export function getWeakTopicQuiz(weakSubjects: string[], count: number = 10): QuizQuestion[] {
  const pool = weakSubjects.flatMap(s => quizBySubject[s] || []);
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, Math.min(count, shuffled.length));
}

